#include<cstdio>
#include<cstring>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10;
int P[N],a[N],FX[N],PS[N],QL[N],QR[N],RK[N],Rt[N],opt[N],n,m;
int topa,topb,lis1[210],lis2[210];
struct HJTree
{
	struct Seg{int l,r,sum;}t[N*50];int cnt;
	inline void build(int l,int r,int &cur)
	{
		cur=++cnt;if(l==r)return;int mid=(l+r)>>1;
		if(l<=mid)build(l,mid,t[cur].l);if(r>mid)build(mid+1,r,t[cur].r);
	}
	inline void Add(int &cur,int pos,int val,int l=1,int r=m)
	{
		t[++cnt]=t[cur];cur=cnt;t[cur].sum+=val;if(l==r)return;int mid=(l+r)>>1;
		pos<=mid?Add(t[cur].l,pos,val,l,mid):Add(t[cur].r,pos,val,mid+1,r);return;
	}
	inline int qry(int k,int l=1,int r=m)
	{
		
		if(l==r)return l;int mid=(l+r)>>1,sum=0;
		rep(1,topa,i)sum+=t[t[lis1[i]].l].sum;rep(1,topb,i)sum-=t[t[lis2[i]].l].sum;
//		printf("qry %d %d %d\n",l,r,sum);
		if(sum>=k)
		{
			rep(1,topa,i)lis1[i]=t[lis1[i]].l;rep(1,topb,i)lis2[i]=t[lis2[i]].l;
			return qry(k,l,mid);
		}
		rep(1,topa,i)lis1[i]=t[lis1[i]].r;rep(1,topb,i)lis2[i]=t[lis2[i]].r;
		return qry(k-sum,mid+1,r);
	}
}t;
inline void add(int x,int pos,int val){while(x<=n)t.Add(Rt[x],pos,val),x+=(x&-x);}
inline int Fnd(int k)
{
	int l=1,r=m,res=1,mid;
	while(l<=r)P[mid=(l+r)>>1]<=k?(l=mid+1,res=mid):(r=mid-1);return res;
}
int main()
{
	n=read();int qq=read(),pp=0;rep(1,n,i)P[++pp]=a[i]=read();
	rep(1,qq,i)
	{
		char ch[3];scanf("%s",ch);
		switch(ch[0])
		{
			case 'Q': QL[i]=read();QR[i]=read();RK[i]=read();break;
			case 'C': opt[i]=1;PS[i]=read();P[++pp]=FX[i]=read();break;
		}
	}
	std::sort(P+1,P+pp+1);m=std::unique(P+1,P+pp+1)-P-1;
	rep(1,n,i)a[i]=Fnd(a[i]);t.build(1,m,Rt[0]);
	rep(1,n,i)Rt[i]=Rt[0];rep(1,n,i)add(i,a[i],1);
//	rep(1,n,i)printf("%d ",a[i]);puts("");
	rep(1,qq,i)
	{
		int x;switch(opt[i])
		{
			case 0: 
				topa=topb=0;
				x=QR[i];while(x)lis1[++topa]=Rt[x],x^=(x&-x); 
				x=QL[i]-1;while(x)lis2[++topb]=Rt[x],x^=(x&-x);
//				printf("%d %d\n",QL[i],QR[i]);
				printf("%d\n",P[t.qry(RK[i])]);break;
			case 1: add(PS[i],a[PS[i]],-1);add(PS[i],a[PS[i]]=Fnd(FX[i]),1);break;
		}
	}
	return 0;
}
